mapper.select:
SELECT d.id, d.order_id AS "orderId", d.customer_id AS "customerId", d.seller_id AS "sellerId", d.dispute_type AS "disputeType", d.reason, d.disputed_amount AS "disputedAmount", d.priority, d.assigned_to AS "assignedTo", d.state_id AS "stateId", d.flow_id AS "flowId", d.created_time AS "createdTime", d.last_modified_time AS "lastModifiedTime", d.resolution_outcome AS "resolutionOutcome", d.resolution_date AS "resolutionDate", d.sla_target_days AS "slaTargetDays", u.first_name || ' ' || u.last_name AS "customerName", u.email AS "customerEmail", s.business_name AS "sellerName" FROM dispute d LEFT JOIN user_profiles u ON d.customer_id = u.id LEFT JOIN supplier s ON d.seller_id = s.id
AND d.dispute_type = #{filters.disputeType} AND d.priority = #{filters.priority} AND d.state_id = #{filters.currentState} AND d.order_id = #{filters.orderId} AND d.seller_id = #{filters.sellerId}
AND (d.id ILIKE '%' || #{searchText} || '%' OR d.order_id ILIKE '%' || #{searchText} || '%' OR u.first_name ILIKE '%' || #{searchText} || '%' OR u.last_name ILIKE '%' || #{searchText} || '%' OR s.business_name ILIKE '%' || #{searchText} || '%')
${orderby} ${pagination}

SELECT count(*)
FROM dispute d
LEFT JOIN user_profiles u ON d.customer_id = u.id
LEFT JOIN supplier s ON d.seller_id = s.id

    AND d.dispute_type = #{filters.disputeType}
    AND d.priority = #{filters.priority}
    AND d.state_id = #{filters.currentState}
    AND d.order_id = #{filters.orderId}
    AND d.seller_id = #{filters.sellerId}

        AND (d.id ILIKE '%' || #{searchText} || '%'
             OR d.order_id ILIKE '%' || #{searchText} || '%')
